"use client"

import { useState } from "react"
import { supabase } from "@/lib/supabase"
import { getFactoryId } from "@/lib/factory"

export function Sales() {
  const [saved, setSaved] = useState(false)

  const [form, setForm] = useState({
    date: new Date().toISOString().split("T")[0],
    customerName: "",
    bagsSold: "",
    pricePerBag: "",
    amountPaid: "",
  })

  const handleSubmit = async () => {
    const factoryId = getFactoryId()

    if (!factoryId) {
      alert("Factory not found")
      return
    }

    if (
      !form.bagsSold ||
      !form.pricePerBag ||
      !form.customerName ||
      !form.amountPaid
    ) {
      alert("Please fill all fields")
      return
    }

    const total =
      Number(form.bagsSold) * Number(form.pricePerBag)

    const paid = Number(form.amountPaid)

    if (paid > total) {
      alert("Amount paid cannot exceed total")
      return
    }

    const balance = total - paid

    // 1️⃣ Save sale
    const { error: saleError } = await supabase.from("sales").insert([
      {
        factory_id: factoryId,
        date: form.date,
        customer_name: form.customerName,
        bags_sold: Number(form.bagsSold),
        price_per_bag: Number(form.pricePerBag),
        total_amount: total,
        amount_paid: paid,
        balance: balance,
      },
    ])

    if (saleError) {
      console.error(saleError)
      alert("Error saving sale")
      return
    }

    // 2️⃣ If balance exists → create debt
    if (balance > 0) {
      const { error: debtError } = await supabase.from("debts").insert([
        {
          factory_id: factoryId,
          customer_name: form.customerName,
          amount: balance,
        },
      ])

      if (debtError) {
        console.error(debtError)
      }
    }

    setSaved(true)

    setTimeout(() => {
      setSaved(false)
      setForm({
        ...form,
        customerName: "",
        bagsSold: "",
        pricePerBag: "",
        amountPaid: "",
      })
    }, 1500)
  }

  const totalPreview =
    Number(form.bagsSold || 0) * Number(form.pricePerBag || 0)

  const balancePreview =
    totalPreview - Number(form.amountPaid || 0)

  return (
    <div className="space-y-4 p-3 pb-20">

      <h1 className="text-lg font-bold text-[#0d1b3e]">Sales</h1>

      <div className="bg-white p-4 rounded-xl shadow-sm space-y-3">

        <input
          type="date"
          value={form.date}
          onChange={(e) => setForm({ ...form, date: e.target.value })}
          className="w-full h-11 border rounded-lg px-3"
        />

        <input
          type="text"
          placeholder="Customer Name"
          value={form.customerName}
          onChange={(e) => setForm({ ...form, customerName: e.target.value })}
          className="w-full h-11 border rounded-lg px-3"
        />

        <input
          type="number"
          placeholder="Bags Sold"
          value={form.bagsSold}
          onChange={(e) => setForm({ ...form, bagsSold: e.target.value })}
          className="w-full h-11 border rounded-lg px-3"
        />

        <input
          type="number"
          placeholder="Price per Bag"
          value={form.pricePerBag}
          onChange={(e) => setForm({ ...form, pricePerBag: e.target.value })}
          className="w-full h-11 border rounded-lg px-3"
        />

        <input
          type="number"
          placeholder="Amount Paid"
          value={form.amountPaid}
          onChange={(e) => setForm({ ...form, amountPaid: e.target.value })}
          className="w-full h-11 border rounded-lg px-3"
        />

        {/* Preview */}
        <div className="bg-gray-50 p-3 rounded-lg text-sm">
          <p>Total: ₦{totalPreview.toLocaleString()}</p>
          <p className={balancePreview > 0 ? "text-red-600" : "text-green-600"}>
            Balance: ₦{balancePreview.toLocaleString()}
          </p>
        </div>

        <button
          onClick={handleSubmit}
          className="w-full h-11 bg-[#2563eb] text-white rounded-lg"
        >
          Save Sale
        </button>

        {saved && (
          <p className="text-green-600 text-sm">Saved successfully</p>
        )}
      </div>
    </div>
  )
}