"use client"

import { useState } from "react"
import { supabase } from "@/lib/supabase"
import { getFactoryId } from "@/lib/factory"

export function Expenses() {
  const [saved, setSaved] = useState(false)

  const [form, setForm] = useState({
    date: new Date().toISOString().split("T")[0],
    category: "",
    amount: "",
    notes: "",
  })

  const handleSubmit = async () => {
    const factoryId = getFactoryId()

    if (!factoryId) {
      alert("Factory not found")
      return
    }

    if (!form.amount || !form.category) {
      alert("Please fill required fields")
      return
    }

    const { error } = await supabase.from("expenses").insert([
      {
        factory_id: factoryId,
        date: form.date,
        category: form.category,
        amount: Number(form.amount),
        notes: form.notes,
      },
    ])

    if (error) {
      console.error(error)
      alert("Error saving expense")
      return
    }

    setSaved(true)

    setTimeout(() => {
      setSaved(false)
      setForm({
        ...form,
        category: "",
        amount: "",
        notes: "",
      })
    }, 1500)
  }

  return (
    <div className="space-y-4 p-3 pb-20">

      <h1 className="text-lg font-bold text-[#0d1b3e]">Expenses</h1>

      <div className="bg-white p-4 rounded-xl shadow-sm space-y-3">

        {/* Date */}
        <input
          type="date"
          value={form.date}
          onChange={(e) => setForm({ ...form, date: e.target.value })}
          className="w-full h-11 border rounded-lg px-3"
        />

        {/* Category */}
        <input
          type="text"
          placeholder="Category (e.g. Diesel)"
          value={form.category}
          onChange={(e) => setForm({ ...form, category: e.target.value })}
          className="w-full h-11 border rounded-lg px-3"
        />

        {/* Amount */}
        <input
          type="number"
          placeholder="Amount"
          value={form.amount}
          onChange={(e) => setForm({ ...form, amount: e.target.value })}
          className="w-full h-11 border rounded-lg px-3"
        />

        {/* Notes */}
        <input
          type="text"
          placeholder="Notes (optional)"
          value={form.notes}
          onChange={(e) => setForm({ ...form, notes: e.target.value })}
          className="w-full h-11 border rounded-lg px-3"
        />

        {/* Save */}
        <button
          onClick={handleSubmit}
          className="w-full h-11 bg-[#2563eb] text-white rounded-lg font-semibold"
        >
          Save Expense
        </button>

        {saved && (
          <p className="text-green-600 text-sm">
            Expense saved successfully
          </p>
        )}
      </div>
    </div>
  )
}